"use strict";

function tryEnterWidgetBlockEditModeAtPos(view, pos) {
	if(!view || typeof pos !== "number") {
		return false;
	}
	const clampedPos = Math.max(0, Math.min(pos, view.state.doc.content.size));

	let domAt;
	try {
		domAt = view.domAtPos(clampedPos);
