function isWidgetBlocksEnabled(wiki) {
	try {
		const sourceWiki = wiki || (typeof $tw !== "undefined" && $tw.wiki);
		if(!sourceWiki) {
			return true;
		}
		const value = (sourceWiki.getTiddlerText("$:/config/prosemirror/enable-widget-blocks", "yes") || "yes").trim();
