function createWidgetBlockPlugin() {
	return new Plugin({
		key: new PluginKey("widgetBlock"),
		state: {
			init(config, state) {
				return DecorationSet.empty;
			},
			apply(tr, set, oldState, newState) {
				if(!isWidgetBlocksEnabled()) {
					return DecorationSet.empty;
