		if(ch === "'") {
			pos++;
			while(pos < str.length && str[pos] !== "'") {
				if(str[pos] === "\\") pos++;
				pos++;
			}
			pos++;
			continue;
		}
		// Check for >>
		if(ch === ">" && str[pos + 1] === ">") {
			return pos;
		}
		pos++;
	}
	return -1;
}

function parseAttributes(str) {
	return parseAttributesDetailed(str).attributes;
}

function parseAttributesDetailed(str) {
	const attributes = {};
	const orderedAttributes = [];
	if(!str) {
		return { attributes: attributes, orderedAttributes: orderedAttributes };
	}
	let pos = 0;
	let paramIndex = 0;
	while(pos < str.length) {
		// Skip whitespace
		while(pos < str.length && /\s/.test(str[pos])) pos++;
		if(pos >= str.length) break;
		// Try to read key=value or key:"value" or key:'value'
		const keyMatch = str.substring(pos).match(/^([a-zA-Z_$][a-zA-Z0-9_$-]*)([:=])/);
		if(keyMatch) {
			const key = keyMatch[1];
			const assignmentOperator = keyMatch[2];
			pos += keyMatch[0].length;
			// Read the value
			const valueResult = readValue(str, pos);
			attributes[key] = valueResult.value;
			orderedAttributes.push({
				name: key,
				value: valueResult.value,
				quoted: !!valueResult.quoted,
				assignmentOperator: assignmentOperator
			});
			pos = valueResult.end;
		} else {
			// Positional argument — use numeric-only name to match TW's convention
			const valueResult = readValue(str, pos);
			if(valueResult.value !== null && valueResult.end > pos) {
				attributes[paramIndex + ""] = valueResult.value;
				orderedAttributes.push({
					name: paramIndex + "",
					value: valueResult.value,
					quoted: !!valueResult.quoted
				});
				paramIndex++;
				pos = valueResult.end;
			} else {
				// Skip a character to avoid infinite loop
				pos++;
			}
		}
	}
	return { attributes: attributes, orderedAttributes: orderedAttributes };
}

function readValue(str, pos) {
	if(pos >= str.length) return { value: null, end: pos };
	// Triple-double-quote
	if(str[pos] === '"' && str[pos + 1] === '"' && str[pos + 2] === '"') {
		const start = pos + 3;
		let end = str.indexOf('"""', start);
		if(end === -1) end = str.length;
		return { value: str.substring(start, end), end: end + 3, quoted: true };
	}
	// Double-quoted
	if(str[pos] === '"') {
		const start = pos + 1;
		let end = start;
		while(end < str.length && str[end] !== '"') {
			if(str[end] === "\\") end++;
			end++;
		}
		return { value: str.substring(start, end), end: end + 1, quoted: true };
	}
	// Single-quoted
	if(str[pos] === "'") {
		const start = pos + 1;
		let end = start;
		while(end < str.length && str[end] !== "'") {
			if(str[end] === "\\") end++;
			end++;
		}
		return { value: str.substring(start, end), end: end + 1, quoted: true };
	}
	// [[double bracket]]
	if(str[pos] === "[" && str[pos + 1] === "[") {
		const start = pos + 2;
		const end = str.indexOf("]]", start);
		if(end !== -1) {
			return { value: str.substring(start, end), end: end + 2 };
		}
	}
	// Unquoted: read until whitespace
	const start = pos;
	while(pos < str.length && !/\s/.test(str[pos])) pos++;
	return { value: str.substring(start, pos), end: pos };
}

function recognizeWidget(line) {
	return parseWidget(line);
}

exports.parseWidget = parseWidget;
exports.parseAttributes = parseAttributes;
exports.recognizeWidget = recognizeWidget;

