/*\
title: $:/plugins/tiddlywiki/prosemirror/features/bubble-menu.js
type: application/javascript
module-type: library

Floating toolbar that appears above text selection for inline formatting.

\*/

"use strict";

const toggleMark = require("prosemirror-commands").toggleMark;

class BubbleMenu {
	constructor(view, schema) {
		this.view = view;
		this.schema = schema;
		this._destroyed = false;
		this._buttons = [];

		// Build the toolbar DOM
		this.el = document.createElement("div");
		this.el.className = "tc-prosemirror-bubble-menu";
		this.el.setAttribute("role", "toolbar");
		this.el.setAttribute("aria-label", "Formatting");
		this.el.style.display = "none";
		document.body.appendChild(this.el);

		this._buildButtons();

		// Prevent mousedown from stealing focus from the editor
		this.el.addEventListener("mousedown", (e) => e.preventDefault());
	}

	_buildButtons() {
		const { schema } = this;
		const items = [];

		if(schema.marks.strong) items.push({ mark: "strong", icon: "$:/core/images/bold", title: "Bold", cmd: toggleMark(schema.marks.strong) });
		if(schema.marks.em) items.push({ mark: "em", icon: "$:/core/images/italic", title: "Italic", cmd: toggleMark(schema.marks.em) });
		if(schema.marks.underline) items.push({ mark: "underline", icon: "$:/core/images/underline", title: "Underline", cmd: toggleMark(schema.marks.underline) });
		if(schema.marks.strike) items.push({ mark: "strike", icon: "$:/core/images/strikethrough", title: "Strikethrough", cmd: toggleMark(schema.marks.strike) });
		if(schema.marks.code) items.push({ mark: "code", icon: "$:/core/images/mono-line", title: "Code", cmd: toggleMark(schema.marks.code) });
		if(schema.marks.link) items.push({ mark: "link", icon: "$:/core/images/link", title: "Link", cmd: null, isLink: true });

		for(const item of items) {
			const btn = document.createElement("button");
			btn.type = "button";
			btn.className = "tc-prosemirror-bubble-btn";
			btn.title = item.title;
			btn.setAttribute("data-mark", item.mark);

			const svgEl = this.constructor._renderSvgIcon(item.icon, "16px");
			if(svgEl) {
				btn.appendChild(svgEl);
			} else {
				btn.textContent = item.title.charAt(0);
			}

			btn.addEventListener("click", (e) => {
				e.preventDefault();
				e.stopPropagation();
				if(item.isLink) {
					this._toggleLink();
				} else if(item.cmd) {
					item.cmd(this.view.state, this.view.dispatch);
					this.view.focus();
					this.update(this.view);
				}
			});

			this.el.appendChild(btn);
			this._buttons.push({ el: btn, mark: item.mark });
		}
	}

	static _renderSvgIcon(tiddlerTitle, size = "16px") {
		try {
			const htmlStr = $tw.wiki.renderTiddler("text/html", tiddlerTitle, { variables: { size } });
			if(!htmlStr) return null;
			const container = document.createElement("div");
			container.innerHTML = htmlStr;
			return container.querySelector("svg");
		} catch(e) {
			return null;
		}
	}

	_toggleLink() {
		const { state, schema } = { state: this.view.state, schema: this.schema };
		if(!schema.marks.link) return;

		const { from, to } = state.selection;
		const linkMark = schema.marks.link.isInSet(state.selection.$from.marks());

		if(linkMark) {
			// Remove existing link
			this.view.dispatch(state.tr.removeMark(from, to, schema.marks.link));
			this.view.focus();
		} else if(!state.selection.empty) {
			// Create wikilink from selected text: [[selectedText]]
			const selectedText = state.doc.textBetween(from, to, "");
			const href = selectedText;
			const mark = schema.marks.link.create({ href: href, title: href });
			this.view.dispatch(state.tr.addMark(from, to, mark));
			this.view.focus();
		}
		this.update(this.view);
	}

	update(view) {
		if(this._destroyed) return;
		this.view = view;
		const { state } = view;
		const sel = state.selection;

		if(sel.empty || sel.$from.pos === sel.$to.pos || sel.$from.parent.type.spec.code) {
			this.el.style.display = "none";
			return;
		}

		this._updateActiveStates(state);

		const start = view.coordsAtPos(sel.from);
		const end = view.coordsAtPos(sel.to);
		const top = Math.min(start.top, end.top);
		const left = (start.left + end.left) / 2;

		this.el.style.display = "flex";
		const menuRect = this.el.getBoundingClientRect();
		this.el.style.position = "absolute";
		this.el.style.left = Math.max(4, left - menuRect.width / 2 + window.scrollX) + "px";
		this.el.style.top = Math.max(4, top - menuRect.height - 8 + window.scrollY) + "px";
		this.el.style.zIndex = "1001";
	}

	_updateActiveStates(state) {
		for(const btn of this._buttons) {
			const markType = this.schema.marks[btn.mark];
			if(!markType) continue;
			btn.el.classList.toggle("tc-prosemirror-bubble-btn-active", this.constructor._isMarkActive(state, markType));
		}
	}

	static _isMarkActive(state, markType) {
		const { from, $from, to, empty } = state.selection;
		if(empty) return !!markType.isInSet(state.storedMarks || $from.marks());
		return state.doc.rangeHasMark(from, to, markType);
	}

	destroy() {
		this._destroyed = true;
		if(this.el && this.el.parentNode) {
			this.el.parentNode.removeChild(this.el);
		}
	}
}

exports.BubbleMenu = BubbleMenu;

/*\
title: $:/plugins/tiddlywiki/prosemirror/features/drag-handle/helpers.js
type: application/javascript
module-type: library

Shared helpers for the ProseMirror drag handle feature.

\*/

"use strict";

const HANDLE_POINTER_BRIDGE = 28;

function lang(suffix, fallback) {
	return $tw.wiki.getTiddlerText(
		"$:/plugins/tiddlywiki/prosemirror/language/DragHandle/" + suffix, fallback);
}

function getSvgIcon(tiddlerTitle, size) {
	size = size || "1em";
	try {
		const htmlStr = $tw.wiki.renderTiddler("text/html", tiddlerTitle, {
			variables: { size: size }
		});
		if(!htmlStr) return null;
		const container = document.createElement("div");
		container.innerHTML = htmlStr;
		const svgEl = container.querySelector("svg");
		if(svgEl) return svgEl;
	} catch(e) { /* ignore */ }
	return null;
}

function isRTL() {
	const dir = document.documentElement.getAttribute("dir");
	return dir === "rtl";
}

function findBlockAtCoords(view, coords) {
	const posInfo = view.posAtCoords(coords);
	if(!posInfo) return null;

	try {
		if(posInfo.inside >= 0) {
			try {
				const innerNode = view.state.doc.nodeAt(posInfo.inside);
				if(innerNode && innerNode.isBlock) {
					const innerDom = view.nodeDOM(posInfo.inside);
					if(innerDom && innerDom.nodeType === 1) {
						return { pos: posInfo.inside, node: innerNode, dom: innerDom, depth: 1 };
					}
				}
			} catch(ex) { /* ignore */ }
		}

		const $pos = view.state.doc.resolve(posInfo.pos);
		for(let depth = $pos.depth; depth >= 1; depth--) {
			const node = $pos.node(depth);
			const pos = $pos.before(depth);
			if(!node.isBlock) continue;
			if(node.type.name === "list") {
				const dom = view.nodeDOM(pos);
				if(dom && dom.nodeType === 1) {
					return { pos: pos, node: node, dom: dom, depth: depth };
				}
			}
			if(depth === 1) {
				const dom1 = view.nodeDOM(pos);
				if(dom1 && dom1.nodeType === 1) {
					return { pos: pos, node: node, dom: dom1, depth: depth };
				}
			}
			if(node.type.spec.atom || node.type.spec.draggable) {
				const domA = view.nodeDOM(pos);
				if(domA && domA.nodeType === 1) {
					return { pos: pos, node: node, dom: domA, depth: depth };
				}
			}
