				label: helpers.lang("TaskList", "Task list"),
				icon: "\u2610",
				iconTiddler: "$:/core/images/done-button",
				action: safeAction((pos, node) => {
					const tr = view.state.tr.setNodeMarkup(pos, null, Object.assign({}, node.attrs, {
