/*\
title: $:/plugins/tiddlywiki/prosemirror/features/link-tooltip.js
type: application/javascript
module-type: library

Floating link tooltip that appears when the cursor is inside a link mark.
Shows the link target and provides edit/open/unlink buttons.

\*/

"use strict";

const { Plugin, PluginKey } = require("prosemirror-state");

const linkTooltipKey = new PluginKey("linkTooltip");

function getLinkAtPos(state) {
	const linkType = state.schema.marks.link;
	if(!linkType) return null;
	const { selection } = state;
	if(!selection.empty) return null;
	const $pos = selection.$from;
	const marks = $pos.marks();
	const linkMark = marks.find((m) => m.type === linkType);
	if(!linkMark) return null;
	// Scan the parent node's children to find the extent of this link mark
	const parentStart = $pos.start();
	let linkFrom = null, linkTo = null;
	$pos.parent.forEach((child, childOffset) => {
		const childFrom = parentStart + childOffset;
		const childTo = childFrom + child.nodeSize;
		if(child.isText && child.marks.some((m) => m.type === linkType && m.attrs.href === linkMark.attrs.href)) {
			if(childFrom <= $pos.pos && $pos.pos <= childTo) {
				linkFrom = childFrom;
				linkTo = childTo;
			} else if(linkFrom !== null && childFrom === linkTo) {
				linkTo = childTo;
			}
		}
	});
	if(linkFrom === null) return null;
	return { mark: linkMark, from: linkFrom, to: linkTo };
}

function getSvgIcon(tiddlerTitle, size) {
	size = size || "1em";
	try {
		const htmlStr = $tw.wiki.renderTiddler("text/html", tiddlerTitle, {
			variables: { size }
		});
		if(!htmlStr) return null;
		const container = document.createElement("div");
		container.innerHTML = htmlStr;
		return container.querySelector("svg") || null;
	} catch(e) {
		return null;
	}
}

function setButtonIcon(button, tiddlerTitle, fallbackText) {
	const svg = getSvgIcon(tiddlerTitle);
	if(svg) {
		button.innerHTML = "";
		button.appendChild(document.importNode(svg, true));
	} else {
		button.textContent = fallbackText || "•";
	}
}

class LinkTooltip {
	constructor(view, parentWidget) {
		this.view = view;
		this.parentWidget = parentWidget;
		this._destroyed = false;
		this._editing = false;
		this._currentLink = null;

		this.el = document.createElement("div");
		this.el.className = "tc-prosemirror-link-tooltip";
		this.el.style.display = "none";
		this.el.setAttribute("contenteditable", "false");
		document.body.appendChild(this.el);

		this.el.addEventListener("mousedown", (e) => {
			e.preventDefault();
			e.stopPropagation();
		});

		this._buildViewMode();
	}

	_buildViewMode() {
		this.el.innerHTML = "";
		this._editing = false;

		const linkDisplay = document.createElement("div");
		linkDisplay.className = "tc-prosemirror-link-tooltip-display";

		this._linkText = document.createElement("a");
		this._linkText.className = "tc-prosemirror-link-tooltip-href";
		this._linkText.target = "_blank";
		this._linkText.rel = "noopener noreferrer";
		linkDisplay.appendChild(this._linkText);

		const btnGroup = document.createElement("span");
		btnGroup.className = "tc-prosemirror-link-tooltip-buttons";

		const editBtn = document.createElement("button");
		editBtn.type = "button";
		editBtn.className = "tc-prosemirror-link-tooltip-btn";
		editBtn.title = "Edit link";
		setButtonIcon(editBtn, "$:/core/images/edit-button", "E");
		editBtn.addEventListener("click", (e) => {
			e.preventDefault();
			this._enterEditMode();
		});
		btnGroup.appendChild(editBtn);

		const openBtn = document.createElement("button");
		openBtn.type = "button";
		openBtn.className = "tc-prosemirror-link-tooltip-btn";
		openBtn.title = "Open link";
		setButtonIcon(openBtn, "$:/core/images/open-window", "\u2197");
		openBtn.addEventListener("click", (e) => {
			e.preventDefault();
			if(!this._currentLink) return;
			const href = this._currentLink.mark.attrs.href || "";
			if(/^(?:https?|ftp|mailto):/i.test(href)) {
				// Check if this is actually an internal link to the same TW instance
				const base = window.location.origin + window.location.pathname;
				if(href.startsWith(base + "#") || href.startsWith(base + "/#")) {
					// Internal wiki link stored as full URL — extract tiddler name
					const hashIdx = href.indexOf("#");
					const tiddler = decodeURIComponent(href.substring(hashIdx + 1));
					this._navigateToTiddler(tiddler);
				} else {
					window.open(href, "_blank", "noopener,noreferrer");
				}
			} else {
				// Internal wiki link — dispatch through the TW widget tree
				this._navigateToTiddler(href);
			}
		});
		btnGroup.appendChild(openBtn);

		const unlinkBtn = document.createElement("button");
		unlinkBtn.type = "button";
		unlinkBtn.className = "tc-prosemirror-link-tooltip-btn tc-prosemirror-link-tooltip-btn-danger";
		unlinkBtn.title = "Remove link";
		setButtonIcon(unlinkBtn, "$:/core/images/close-button", "\u00D7");
		unlinkBtn.addEventListener("click", (e) => {
			e.preventDefault();
			if(!this._currentLink) return;
			const { state } = this.view;
			this.view.dispatch(state.tr.removeMark(this._currentLink.from, this._currentLink.to, state.schema.marks.link));
			this.view.focus();
		});
		btnGroup.appendChild(unlinkBtn);

		linkDisplay.appendChild(btnGroup);
		this.el.appendChild(linkDisplay);
	}

	_navigateToTiddler(tiddlerName) {
		const widget = this.parentWidget;
		if(widget) {
			widget.dispatchEvent({
				type: "tm-navigate",
				navigateTo: tiddlerName,
				navigateFromTitle: widget.getVariable("storyTiddler")
			});
		}
	}

	_enterEditMode() {
		if(!this._currentLink) return;
		this._editing = true;
		this.el.innerHTML = "";

		const form = document.createElement("div");
		form.className = "tc-prosemirror-link-tooltip-edit";

		const input = document.createElement("input");
		input.type = "text";
		input.className = "tc-prosemirror-link-tooltip-input";
		input.value = this._currentLink.mark.attrs.href || "";
		input.placeholder = "Link target...";
		form.appendChild(input);

		const okBtn = document.createElement("button");
		okBtn.type = "button";
		okBtn.className = "tc-prosemirror-link-tooltip-btn tc-prosemirror-link-tooltip-btn-ok";
		setButtonIcon(okBtn, "$:/core/images/done-button", "\u2713");
		okBtn.title = "Confirm";
		okBtn.addEventListener("click", (e) => {
			e.preventDefault();
			this._commitEdit(input.value);
		});
		form.appendChild(okBtn);

		const cancelBtn = document.createElement("button");
		cancelBtn.type = "button";
		cancelBtn.className = "tc-prosemirror-link-tooltip-btn";
		setButtonIcon(cancelBtn, "$:/core/images/cancel-button", "\u00D7");
		cancelBtn.title = "Cancel";
		cancelBtn.addEventListener("click", (e) => {
			e.preventDefault();
			this._editing = false;
			this._buildViewMode();
			this.update(this.view);
		});
		form.appendChild(cancelBtn);

		this.el.appendChild(form);

		setTimeout(() => { input.focus(); input.select(); }, 0);

		input.addEventListener("keydown", (e) => {
			if(e.key === "Enter") {
				e.preventDefault();
				this._commitEdit(input.value);
			} else if(e.key === "Escape") {
				e.preventDefault();
				this._editing = false;
				this._buildViewMode();
				this.update(this.view);
				this.view.focus();
			}
		});
	}

	_commitEdit(newHref) {
		if(!this._currentLink) return;
		const { state } = this.view;
		const linkType = state.schema.marks.link;
		const { from, to } = this._currentLink;
		let tr = state.tr.removeMark(from, to, linkType);
		const trimmed = (newHref || "").trim();
		if(trimmed) {
			tr = tr.addMark(from, to, linkType.create({ href: trimmed, title: trimmed }));
		}
		this.view.dispatch(tr);
		this._editing = false;
		this._buildViewMode();
		this.view.focus();
	}

	update(view) {
		if(this._destroyed) return;
		this.view = view;
		if(this._editing) return;

		const linkInfo = getLinkAtPos(view.state);
		if(!linkInfo) {
			this.el.style.display = "none";
			this._currentLink = null;
			return;
		}

		this._currentLink = linkInfo;
		const href = linkInfo.mark.attrs.href || "";
		const isExternal = /^(?:https?|ftp|mailto):/i.test(href);
		this._linkText.textContent = href;
		this._linkText.href = isExternal ? href : `#${encodeURIComponent(href)}`;
		this._linkText.target = isExternal ? "_blank" : "_self";

		const coords = view.coordsAtPos(linkInfo.from);
		const endCoords = view.coordsAtPos(linkInfo.to);
		const left = (coords.left + endCoords.left) / 2;
		const top = Math.max(coords.bottom, endCoords.bottom);

		this.el.style.display = "flex";
		const rect = this.el.getBoundingClientRect();
		this.el.style.position = "absolute";
		this.el.style.left = `${Math.max(4, left - rect.width / 2 + window.scrollX)}px`;
		this.el.style.top = `${top + 4 + window.scrollY}px`;
		this.el.style.zIndex = "1002";
	}

	destroy() {
		this._destroyed = true;
		if(this.el && this.el.parentNode) {
			this.el.parentNode.removeChild(this.el);
		}
	}
}

function createLinkTooltipPlugin(parentWidget) {
	let tooltipInstance = null;
	return new Plugin({
		key: linkTooltipKey,
		view(editorView) {
			tooltipInstance = new LinkTooltip(editorView, parentWidget);
			return {
				update(view) {
					tooltipInstance.update(view);
				},
				destroy() {
					tooltipInstance.destroy();
				}
			};
		}
	});
}

exports.createLinkTooltipPlugin = createLinkTooltipPlugin;
exports.LinkTooltip = LinkTooltip;

/*\
title: $:/plugins/tiddlywiki/prosemirror/features/markdown-shortcuts.js
type: application/javascript
module-type: library

Markdown-style input rules for ProseMirror.
Converts **bold**, *italic*, ~~strike~~, `code` etc. into PM marks.
These produce wikitext-native marks (not Markdown) so the output is always wikitext.
Enabled/disabled via $:/config/prosemirror/markdown-shortcuts.

\*/

"use strict";

const InputRule = require("prosemirror-inputrules").InputRule;
const TextSelection = require("prosemirror-state").TextSelection;

const GLOBAL_MARKDOWN_SHORTCUTS_TITLE = "$:/config/prosemirror/markdown-shortcuts";
const AUTO_MARKDOWN_SHORTCUTS_FOR_MARKDOWN_TITLE = "$:/config/prosemirror/markdown-shortcuts/auto-for-markdown";

function isMarkdownEditorType(editorType) {
	if(!editorType) return false;
	const normalizedType = editorType.trim().toLowerCase();
	return normalizedType === "text/markdown" || normalizedType === "text/x-markdown";
}

function shouldEnableMarkdownShortcuts(wiki, editorType) {
	const explicitSetting = wiki.getTiddlerText(GLOBAL_MARKDOWN_SHORTCUTS_TITLE, "no").trim().toLowerCase();
	if(explicitSetting === "yes") {
		return true;
	}
	const autoForMarkdown = wiki.getTiddlerText(AUTO_MARKDOWN_SHORTCUTS_FOR_MARKDOWN_TITLE, "yes").trim().toLowerCase();
	return autoForMarkdown === "yes" && isMarkdownEditorType(editorType);
}

function markInputRule(regexp, markType, groupIndex) {
	groupIndex = groupIndex || 1;
	return new InputRule(regexp, (state, match, start, end) => {
		const innerText = match[groupIndex];
		if(!innerText) return null;
		const tr = state.tr;
		// Replace the full matched text with just the inner text + mark
		tr.delete(start, end);
		tr.insertText(innerText, start);
		const markFrom = start;
		const markTo = start + innerText.length;
		tr.addMark(markFrom, markTo, markType.create());
		// Move cursor after the marked text
		tr.setSelection(TextSelection.create(tr.doc, markTo));
		// Remove stored marks so next typing is unmarked
		tr.removeStoredMark(markType);
		return tr;
	});
}

function headingInputRule(schema) {
	const headingType = schema.nodes.heading;
	if(!headingType) return [];
	return [
		// # Heading 1 (must be at start of textblock; triggered by Space)
		new InputRule(/^#\s$/, (state, match, start, end) => state.tr.delete(start, end).setBlockType(start, start, headingType, { level: 1 })),
		new InputRule(/^##\s$/, (state, match, start, end) => state.tr.delete(start, end).setBlockType(start, start, headingType, { level: 2 })),
		new InputRule(/^###\s$/, (state, match, start, end) => state.tr.delete(start, end).setBlockType(start, start, headingType, { level: 3 })),
		new InputRule(/^####\s$/, (state, match, start, end) => state.tr.delete(start, end).setBlockType(start, start, headingType, { level: 4 })),
		new InputRule(/^#####\s$/, (state, match, start, end) => state.tr.delete(start, end).setBlockType(start, start, headingType, { level: 5 })),
		new InputRule(/^######\s$/, (state, match, start, end) => state.tr.delete(start, end).setBlockType(start, start, headingType, { level: 6 }))
	];
}

function hrInputRule(schema) {
	const hrType = schema.nodes.horizontal_rule;
	if(!hrType) return [];
	return [
		new InputRule(/^---$/, (state, match, start, end) => state.tr.replaceWith(start - 1, end, [
			hrType.create(),
			schema.nodes.paragraph.createAndFill()
		]))
	];
}

function codeBlockInputRule(schema) {
	const cbType = schema.nodes.code_block;
	if(!cbType) return [];
	return [
		new InputRule(/^```$/, (state, match, start, end) => state.tr.delete(start - 1, end).setBlockType(start - 1, start - 1, cbType))
	];
}

function getMarkdownInputRules(wiki, schema, editorType) {
	if(!shouldEnableMarkdownShortcuts(wiki, editorType)) return [];

	let rules = [];
	const marks = schema.marks;

	// **bold** 
	if(marks.strong) {
		rules.push(markInputRule(/\*\*([^\*]+)\*\*$/, marks.strong));
	}
	// *italic* (only single asterisk — match when preceded by whitespace or start of line)
	if(marks.em) {
		rules.push(markInputRule(/(?:^|[\s\u00A0])\*([^\*]+)\*$/, marks.em));
	}
	// ~~strikethrough~~
	if(marks.strike) {
		rules.push(markInputRule(/~~([^~]+)~~$/, marks.strike));
	}
	// `code`
	if(marks.code) {
		rules.push(markInputRule(/`([^`]+)`$/, marks.code));
	}

	// Heading shortcuts: # ## ### etc.
	rules = rules.concat(headingInputRule(schema));

	// Horizontal rule: ---
	rules = rules.concat(hrInputRule(schema));

	// Code block: ```
	rules = rules.concat(codeBlockInputRule(schema));

	// Definition list shortcuts: ; and ：for term, : and ： for description
	rules = rules.concat(definitionListInputRules(schema, wiki));

	return rules;
}

function definitionListInputRules(schema, wiki) {
	let rules = [];
	const dtType = schema.nodes.definition_term;
	const ddType = schema.nodes.definition_description;
	const dlType = schema.nodes.definition_list;
	if(!dtType || !ddType || !dlType) return rules;

	// Default triggers: ; and ；for <dt>, : and ：for <dd>
	const termTriggers = parseTriggerList(wiki, "$:/config/prosemirror/def-term-triggers", [";", "；"]);
	const descTriggers = parseTriggerList(wiki, "$:/config/prosemirror/def-desc-triggers", [":", "："]);

	termTriggers.forEach((trig) => {
		const escaped = trig.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
		const pattern = new RegExp("^" + escaped + "\\s$");
		rules.push(new InputRule(pattern, (state, match, start, end) => createDefListItem(state, start, end, dlType, dtType)));
	});

	descTriggers.forEach((trig) => {
		const escaped = trig.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
		const pattern = new RegExp("^" + escaped + "\\s$");
		rules.push(new InputRule(pattern, (state, match, start, end) => createDefListItem(state, start, end, dlType, ddType)));
	});

	return rules;
}

function parseTriggerList(wiki, title, defaults) {
	const text = wiki.getTiddlerText(title, "");
	if(!text.trim()) return defaults;
	return text.split(/\s+/).map((s) => s.trim()).filter((s) => s.length > 0);
}

function createDefListItem(state, start, end, dlType, itemType) {
	const $pos = state.doc.resolve(start);
	// Only convert if we're in a paragraph that's a direct child of doc or a definition_list
	if(!$pos.parent.isTextblock) return null;
	let tr = state.tr.delete(start, end);
	// Replace the paragraph with a definition_list containing the item
	const blockStart = $pos.before($pos.depth);
	const blockEnd = $pos.after($pos.depth);
	const dl = dlType.create(null, [itemType.create()]);
	tr = tr.replaceWith(blockStart, blockEnd, dl);
	// Place cursor inside the new item
	return tr.setSelection(TextSelection.create(tr.doc, blockStart + 2));
}

exports.getMarkdownInputRules = getMarkdownInputRules;
exports.shouldEnableMarkdownShortcuts = shouldEnableMarkdownShortcuts;

/*\
title: $:/plugins/tiddlywiki/prosemirror/features/slash-menu/menu-elements.js
type: application/javascript
module-type: library

Exports functions to get all menu elements for SlashMenu (default + snippets + EditorAction tiddlers)
\*/

"use strict";

const TextSelection = require("prosemirror-state").TextSelection;
const parseWidget = require("$:/plugins/tiddlywiki/prosemirror/blocks/widget/utils.js").parseWidget;
const scheduleEnterWidgetBlockEditModeNearSelection = require("$:/plugins/tiddlywiki/prosemirror/blocks/widget/actions.js").scheduleEnterWidgetBlockEditModeNearSelection;
const scheduleNextAutoEdit = require("$:/plugins/tiddlywiki/prosemirror/blocks/typed-block/nodeview.js").scheduleNextAutoEdit;

const EDITOR_ACTION_TAG = "$:/tags/ProseMirror/EditorAction";

function getBuiltinActionCommands(schema) {
	const pmCommands = require("prosemirror-commands");
	return {
		"codeblock": (view) => {
			const current = view.state.selection.$from.parent;
			if(current.type === schema.nodes.code_block) {
				pmCommands.setBlockType(schema.nodes.paragraph)(view.state, view.dispatch);
			} else {
				pmCommands.setBlockType(schema.nodes.code_block)(view.state, view.dispatch);
			}
			return true;
		},
		"blockquote": (view) => {
			const $from = view.state.selection.$from;
			for(let d = $from.depth; d > 0; d--) {
				if($from.node(d).type === schema.nodes.blockquote) {
					pmCommands.lift(view.state, view.dispatch);
					return true;
				}
			}
			pmCommands.wrapIn(schema.nodes.blockquote)(view.state, view.dispatch);
			return true;
		},
		"paragraph": (view) => {
			pmCommands.setBlockType(schema.nodes.paragraph)(view.state, view.dispatch);
			return true;
		},
		"heading1": (view) => { pmCommands.setBlockType(schema.nodes.heading, { level: 1 })(view.state, view.dispatch); return true; },
		"heading2": (view) => { pmCommands.setBlockType(schema.nodes.heading, { level: 2 })(view.state, view.dispatch); return true; },
		"heading3": (view) => { pmCommands.setBlockType(schema.nodes.heading, { level: 3 })(view.state, view.dispatch); return true; },
		"heading4": (view) => { pmCommands.setBlockType(schema.nodes.heading, { level: 4 })(view.state, view.dispatch); return true; },
		"heading5": (view) => { pmCommands.setBlockType(schema.nodes.heading, { level: 5 })(view.state, view.dispatch); return true; },
		"heading6": (view) => { pmCommands.setBlockType(schema.nodes.heading, { level: 6 })(view.state, view.dispatch); return true; },
		"horizontal-rule": (view) => {
			const tr = view.state.tr.replaceSelectionWith(schema.nodes.horizontal_rule.create());
			view.dispatch(tr);
			return true;
		},
		"bold": (view) => { pmCommands.toggleMark(schema.marks.strong)(view.state, view.dispatch); return true; },
		"italic": (view) => { pmCommands.toggleMark(schema.marks.em)(view.state, view.dispatch); return true; },
		"underline": (view) => { if(schema.marks.underline) { pmCommands.toggleMark(schema.marks.underline)(view.state, view.dispatch); } return true; },
		"strikethrough": (view) => { if(schema.marks.strike) { pmCommands.toggleMark(schema.marks.strike)(view.state, view.dispatch); } return true; },
		"code-inline": (view) => { pmCommands.toggleMark(schema.marks.code)(view.state, view.dispatch); return true; },
		"insert-table": (view) => {
			if(!schema.nodes.table || !schema.nodes.table_row || !schema.nodes.table_cell || !schema.nodes.table_header) return false;
			// Create a 3×3 table with header row
			const headerCells = [];
			let dataCells = [];
			for(let c = 0; c < 3; c++) {
				headerCells.push(schema.nodes.table_header.createAndFill());
				dataCells.push(schema.nodes.table_cell.createAndFill());
			}
			const headerRow = schema.nodes.table_row.create(null, headerCells);
			const dataRow1 = schema.nodes.table_row.create(null, dataCells);
			dataCells = [];
			for(let c2 = 0; c2 < 3; c2++) {
				dataCells.push(schema.nodes.table_cell.createAndFill());
			}
			const dataRow2 = schema.nodes.table_row.create(null, dataCells);
			const table = schema.nodes.table.create(null, [headerRow, dataRow1, dataRow2]);
