$:/plugins/tiddlywiki/prosemirror/slash-.text:
\rules only filteredtranscludeinline transcludeinline macrodef macrocallinline macrocallblock

.tw-slash-menu-root {
	background-color: <<colour tiddler-editor-background>>;
	border-color: <<colour tiddler-editor-border>>;
	color: <<colour foreground>>;
}

.tw-slash-menu-filter-wrapper {
	background-color: <<colour page-background>>;
	border-bottom-color: <<colour tiddler-editor-border>>;
}

.tw-slash-menu-filter {
	color: <<colour muted-foreground>>;
}

.tw-slash-menu-item-description {
	color: <<colour muted-foreground>>;
}

.tw-slash-menu-item-icon svg {
	fill: <<colour foreground>>;
}

.tw-slash-menu-item:hover,
.tw-slash-menu-item-selected {
	background-color: <<colour tiddler-editor-fields-even>>;
}

.tw-slash-menu-item-icon {
	color: <<colour muted-foreground>>;
}

.tw-slash-menu-item-label {
	color: <<colour foreground>>;
}

.tw-slash-menu-placeholder {
	color: <<colour muted-foreground>>;
}

.tw-slash-menu-group-title {
	color: <<colour foreground>>;
	border-bottom-color: <<colour tiddler-editor-border>>;
	background: <<colour page-background>>;
}

/* SlashMenu UI structural styles — colours in slash-menu-ui.color.tid */
.tw-slash-menu-root {
	position: absolute;
	display: flex;
	flex-direction: column;
	max-height: 280px;
	width: 250px;
	z-index: 1000;
	/* outer container is NOT scrollable; the filter row stays pinned at the top */
	overflow: hidden;
	border-radius: 6px;
	border: 1px solid transparent;
	box-shadow: 0 10px 15px -3px rgba(0, 0, 0, 0.1), 0 4px 6px -2px rgba(0, 0, 0, 0.05);
	font-size: 14px;
}

.tw-slash-menu-filter-wrapper {
	flex: 0 0 auto;
	display: flex;
	padding: 8px 12px;
	border-bottom: 1px solid transparent;
	align-items: center;
}

.tw-slash-menu-filter {
	font-style: italic;
}

.tw-slash-menu-content {
	flex: 1 1 auto;
	min-height: 0;
	overflow-y: auto;
	padding: 4px;
}

.tw-slash-menu-item {
	display: flex;
	align-items: center;
	padding: 8px 12px;
	border-radius: 4px;
	cursor: default;
	transition: background-color 0.15s ease;
}

.tw-slash-menu-item-clickable {
	cursor: pointer;
}

.tw-slash-menu-item-icon {
	width: 20px;
	height: 20px;
	display: flex;
	align-items: center;
	justify-content: center;
	margin-right: 8px;
	font-size: 12px;
}

.tw-slash-menu-item-label {
	flex: 1;
	font-weight: 500;
}

.tw-slash-menu-item-description {
	font-size: 0.8em;
	line-height: 1.3;
}

.tw-slash-menu-item-text {
	display: flex;
	flex-direction: column;
	gap: 1px;
}

.tw-slash-menu-placeholder {
	text-align: center;
	padding: 16px 12px;
	font-style: italic;
}

.tw-slash-menu-group-title {
	font-size: 13px;
	font-weight: bold;
	padding: 8px 12px 2px 12px;
	margin-top: 8px;
	margin-bottom: 2px;
	border-bottom: 1px solid transparent;
	letter-spacing: 0.5px;
}

html[dir="rtl"] .tw-slash-menu-root {
	direction: rtl;
	text-align: right;
}

