test-prosemirror-ast-roundtrip.js.text:
/*\
title: test-prosemirror-ast-roundtrip.js
type: application/javascript
tags: [[$:/tags/test-spec]]

Tests the ProseMirror AST round-trip: wikitext → wiki AST → PM AST → wiki AST → wikitext.
Ensures content is not lost or corrupted when editing in the WYSIWYG editor.

\*/

if(!$tw.browser) {
	// These tests require the wikitext-serialize plugin which is available in both
	// browser and node environments, but the prosemirror AST converters should work in node too.
	describe("ProseMirror AST round-trip tests", () => {

		let wikiAstToProseMirrorAst, wikiAstFromProseMirrorAst;
		try {
			wikiAstToProseMirrorAst = require("$:/plugins/tiddlywiki/prosemirror/ast/to-prosemirror.js").to;
			wikiAstFromProseMirrorAst = require("$:/plugins/tiddlywiki/prosemirror/ast/from-prosemirror.js").from;
		} catch(e) {
			// If running in node and prosemirror libs aren't available, skip
			return;
		}

		function roundTrip(wikitext) {
			const parseResult = $tw.wiki.parseText("text/vnd.tiddlywiki", wikitext);
			const wikiAst = parseResult.tree;
			const pmAst = wikiAstToProseMirrorAst(wikiAst);
			// pmAst is a doc object; fromPM expects the doc's content array or the doc itself
			let restored;
			if(pmAst && pmAst.type === "doc" && pmAst.content) {
				restored = wikiAstFromProseMirrorAst(pmAst);
			} else {
				restored = wikiAstFromProseMirrorAst(pmAst);
			}
			return $tw.utils.serializeWikitextParseTree(restored).trimEnd();
		}

		// --- Basic inline formatting ---

		it("should round-trip bold text", () => {
			expect(roundTrip("''bold text''")).toBe("''bold text''");
		});

		it("should round-trip italic text", () => {
			expect(roundTrip("//italic text//")).toBe("//italic text//");
		});

		it("should round-trip bold+italic text", () => {
			const input = "''//bold italic//''";
			const result = roundTrip(input);
			// Both orderings are acceptable
			expect(result === "''//bold italic//''" || result === "//''bold italic''//").toBe(true);
		});

		it("should round-trip underline text", () => {
			expect(roundTrip("__underlined__")).toBe("__underlined__");
		});

		it("should round-trip strikethrough text", () => {
			expect(roundTrip("~~strikethrough~~")).toBe("~~strikethrough~~");
		});

		it("should round-trip superscript text", () => {
			expect(roundTrip("^^superscript^^")).toBe("^^superscript^^");
		});

		it("should round-trip subscript text", () => {
			expect(roundTrip(",,subscript,,")).toBe(",,subscript,,");
		});

		it("should round-trip inline code", () => {
			expect(roundTrip("`code`")).toBe("`code`");
		});

		// --- Headings ---

		it("should round-trip heading levels 1-6", () => {
			for(let i = 1; i <= 6; i++) {
				let prefix = "";
				for(let j = 0; j < i; j++) prefix += "!";
				const input = prefix + " Heading " + i;
				expect(roundTrip(input)).toBe(input);
			}
		});

		// --- Lists ---

		it("should round-trip bullet list", () => {
			const input = "* Item 1\n* Item 2\n* Item 3";
			expect(roundTrip(input)).toBe(input);
		});

		it("should round-trip ordered list", () => {
			const input = "# Item 1\n# Item 2\n# Item 3";
			expect(roundTrip(input)).toBe(input);
		});

		// --- Code blocks ---

		it("should round-trip code block", () => {
			const input = "```\nvar x = 1;\nconsole.log(x);\n```";
			const result = roundTrip(input);
			// Code block content should be preserved
			expect(result).toContain("var x = 1;");
			expect(result).toContain("console.log(x);");
		});

		// --- Block elements ---

		it("should round-trip hard line breaks block", () => {
			const input = '"""\nThis is some text\nThat is set like\nIt is a Poem\n"""';
			const result = roundTrip(input);
			expect(result).toContain('"""');
			expect(result).toContain("This is some text");
			expect(result).toContain("That is set like");
		});

		it("should round-trip typed block", () => {
			const input = '$$$application/javascript\nconsole.log("test");\n$$$';
			const result = roundTrip(input);
			expect(result).toContain("$$$application/javascript");
			expect(result).toContain('console.log("test");');
			expect(result).toContain("$$$");
		});

		it("should round-trip horizontal rule", () => {
			const input = "text above\n\n---\n\ntext below";
			const result = roundTrip(input);
			expect(result).toContain("---");
		});

		it("should round-trip blockquote", () => {
			const input = "<<<\nquoted text\n<<<";
			const result = roundTrip(input);
			expect(result).toContain("quoted text");
		});

		it("should round-trip blockquote with cite", () => {
			const input = "<<<\nquoted text\n<<<citation source";
			const result = roundTrip(input);
			expect(result).toContain("quoted text");
			expect(result).toContain("citation source");
		});

		// --- Links ---

		it("should round-trip internal link", () => {
			const input = "Click [[here|MyTiddler]] to go";
			const result = roundTrip(input);
			expect(result).toContain("[[here|MyTiddler]]");
		});

		it("should round-trip external link", () => {
			const input = "Visit [ext[example|https://example.com]]";
			const result = roundTrip(input);
			expect(result).toContain("https://example.com");
		});

		// --- Images ---

		it("should round-trip image shortcut", () => {
			const input = "[img[myimage.png]]";
			const result = roundTrip(input);
			expect(result).toContain("myimage.png");
		});

		// --- Macros / Widgets ---

		it("should round-trip simple macro call", () => {
			const input = "<<myMacro>>";
			const result = roundTrip(input);
			expect(result).toContain("myMacro");
		});

		it("should round-trip macro call with parameters", () => {
			const input = '<<myMacro "param1" key:"value">>';
			const result = roundTrip(input);
			expect(result).toContain("myMacro");
		});

		it("should round-trip macro with positional filter argument", () => {
			const input = '<<list-links "[tag[task]sort[title]]">>';
			const result = roundTrip(input);
			expect(result).toBe('<<list-links "[tag[task]sort[title]]">>');
		});

		// --- Pragmas ---

		it("should preserve \\define pragma", () => {
			const input = "\\define myMacro()\nHello World\n\\end\n\nBody text";
			const result = roundTrip(input);
			expect(result).toContain("\\define");
			expect(result).toContain("myMacro");
			expect(result).toContain("Body text");
		});

		it("should preserve \\procedure pragma", () => {
			const input = "\\procedure myProc(param1)\nProcedure body\n\\end\n\nContent after";
			const result = roundTrip(input);
			expect(result).toContain("\\procedure");
			expect(result).toContain("myProc");
			expect(result).toContain("Content after");
		});

		it("should preserve \\import pragma", () => {
			const input = "\\import [tag[macros]]\n\nBody text here";
			const result = roundTrip(input);
			expect(result).toContain("\\import");
			expect(result).toContain("[tag[macros]]");
			expect(result).toContain("Body text here");
		});

		// --- Table round-trip ---

		it("should round-trip a simple table", () => {
			const input = "|!Header 1|!Header 2|\n|Cell 1|Cell 2|\n";
			const result = roundTrip(input);
			expect(result).toContain("|!Header 1|!Header 2|");
			expect(result).toContain("|Cell 1|Cell 2|");
		});

		it("should round-trip a table with mixed content", () => {
			const input = "|!Header 1|!Header 2|\n|Cell 1|Cell 2|\n\nAfter table";
			const result = roundTrip(input);
			// Table content should not be lost
			expect(result).toContain("Header 1");
			expect(result).toContain("Cell 1");
			expect(result).toContain("After table");
		});

		it("should round-trip a table with only data cells", () => {
			const input = "|A|B|\n|C|D|\n";
			const result = roundTrip(input);
			expect(result).toContain("|A|B|");
			expect(result).toContain("|C|D|");
		});

		it("should round-trip a single-row table", () => {
			const input = "|!Solo Header|\n";
			const result = roundTrip(input);
			expect(result).toContain("|!Solo Header|");
		});

		// --- Mixed content ---

		it("should handle mixed content without data loss", () => {
			const input = "! Heading\n\nNormal paragraph with ''bold'' and //italic//.\n\n* List item 1\n* List item 2\n\n---\n\nEnd.";
			const result = roundTrip(input);
			expect(result).toContain("Heading");
			expect(result).toContain("bold");
			expect(result).toContain("italic");
			expect(result).toContain("List item");
			expect(result).toContain("---");
			expect(result).toContain("End.");
		});

		// --- Empty and edge cases ---

		it("should handle empty document", () => {
			const result = roundTrip("");
			// Should produce at least an empty string or whitespace
			expect(typeof result).toBe("string");
		});

		it("should handle plain text without formatting", () => {
			expect(roundTrip("Just plain text.")).toBe("Just plain text.");
		});

		// --- Pragma edge cases ---

		it("should not duplicate body text after \\define", () => {
			const input = "\\define myMacro()\nHello World\n\\end\n\nBody text";
			const result = roundTrip(input);
			// Body text should appear exactly once
			const count = result.split("Body text").length - 1;
			expect(count).toBe(1);
		});

		it("should not duplicate body text after \\procedure", () => {
			const input = "\\procedure myProc(param1)\nProcedure body\n\\end\n\nContent after";
			const result = roundTrip(input);
			const count = result.split("Content after").length - 1;
			expect(count).toBe(1);
		});

		it("should preserve multiple pragmas", () => {
			const input = "\\define foo()\nfoo body\n\\end\n\\define bar()\nbar body\n\\end\n\nMain content";
			const result = roundTrip(input);
			expect(result).toContain("foo");
			expect(result).toContain("bar");
			expect(result).toContain("Main content");
			// Ensure content isn't duplicated
			const count = result.split("Main content").length - 1;
			expect(count).toBe(1);
		});

		// --- Entity round-trip ---

		it("should preserve content with en-dash entity", () => {
			const input = "Pages 10&ndash;20";
			const result = roundTrip(input);
			// The en-dash should be preserved (either as entity or as unicode char)
			expect(result.length).toBeGreaterThan(5);
		});

		// --- Transclusion preservation ---

		it("should preserve tiddler transclusion", () => {
			const input = "{{MyTiddler}}";
			const result = roundTrip(input);
			expect(result).toContain("MyTiddler");
		});

		it("should preserve template transclusion", () => {
			const input = "{{||MyTemplate}}";
			const result = roundTrip(input);
			expect(result).toContain("MyTemplate");
		});

		// --- Hard break (Shift-Enter) ---

		it("should round-trip hard break (line break within paragraph)", () => {
			const input = "Line one\nLine two";
			const result = roundTrip(input);
			// Hard break or soft newline should be preserved
			expect(result).toContain("Line one");
			expect(result).toContain("Line two");
		});

		// --- Nested formatting ---

		it("should round-trip bold within list item", () => {
			const input = "* Item with ''bold'' text\n* Normal item";
			const result = roundTrip(input);
			expect(result).toContain("bold");
			expect(result).toContain("Normal item");
		});

		it("should round-trip link within heading", () => {
			const input = "! Heading with [[link|target]]";
			const result = roundTrip(input);
			expect(result).toContain("Heading");
			expect(result).toContain("link");
		});

		// --- Multiple paragraphs ---

		it("should preserve multiple paragraphs separated by blank lines", () => {
			const input = "First paragraph.\n\nSecond paragraph.\n\nThird paragraph.";
			const result = roundTrip(input);
			expect(result).toContain("First paragraph.");
			expect(result).toContain("Second paragraph.");
			expect(result).toContain("Third paragraph.");
		});

		// --- Nested lists ---

		it("should round-trip nested bullet lists", () => {
			const input = "* Item 1\n** Sub-item 1\n** Sub-item 2\n* Item 2";
			const result = roundTrip(input);
			expect(result).toContain("Item 1");
			expect(result).toContain("Sub-item 1");
			expect(result).toContain("Item 2");
		});

		// --- Mixed list types ---

		it("should round-trip mixed list types", () => {
			const input = "* Bullet\n# Number";
			const result = roundTrip(input);
			expect(result).toContain("Bullet");
			expect(result).toContain("Number");
		});

		// --- Inline code within formatted text ---

		it("should round-trip inline code", () => {
			const input = "Use `console.log()` for debugging";
			const result = roundTrip(input);
			expect(result).toContain("console.log()");
		});

		// --- Widget/transclusion edge cases ---

		it("should preserve widget with $ prefix", () => {
			const input = "<$list filter=\"[tag[test]]\">\nContent\n</$list>";
			const result = roundTrip(input);
			expect(result).toContain("$list");
			expect(result).toContain("tag[test]");
		});

		it("should preserve filter transclusion", () => {
			const input = "{{{ [tag[task]] }}}";
			const result = roundTrip(input);
			expect(result).toContain("tag[task]");
		});

		// --- Extreme edge cases ---

		it("should handle document with only whitespace", () => {
			const result = roundTrip("   ");
			expect(typeof result).toBe("string");
		});

		it("should handle single character document", () => {
			expect(roundTrip("x")).toBe("x");
		});

		it("should preserve special characters in text", () => {
			const input = "Text with <angle> & \"quotes\" and 'apostrophes'";
			const result = roundTrip(input);
			expect(result).toContain("angle");
			expect(result).toContain("quotes");
		});

		// --- Definition lists ---

		it("should round-trip definition list", () => {
			const input = "; Term\n: Definition";
			const result = roundTrip(input);
			expect(result).toContain("Term");
			expect(result).toContain("Definition");
		});

		it("should round-trip multiple definition pairs", () => {
			const input = "; Apple\n: A fruit\n; Banana\n: Another fruit";
			const result = roundTrip(input);
			expect(result).toContain("Apple");
			expect(result).toContain("A fruit");
			expect(result).toContain("Banana");
			expect(result).toContain("Another fruit");
		});
	});
}

test-prosemirror-editor-mapping.js.text:
/*\
title: test-prosemirror-editor-mapping.js
type: application/javascript
tags: [[$:/tags/test-spec]]

Tests for editor type fallback integration with ProseMirror mapping.
\*/

"use strict";

describe("ProseMirror editor mapping fallback", function() {
	function withBrowserFlag(value, callback) {
		var originalBrowser = $tw.browser;
		$tw.browser = value;
		try {
			callback();
		} finally{
			$tw.browser = originalBrowser;
		}
	}

	it("should fall back to text editor outside the browser when mapped to prosemirror", function() {
		var EditWidget = require("$:/core/modules/widgets/edit.js").edit;
		var wiki = new $tw.Wiki();
		wiki.addTiddler({
			title: "$:/config/EditorTypeMappings/text/vnd.tiddlywiki",
			text: "prosemirror"
		});
		wiki.addTiddler({
			title: "MappingFallbackTest",
			text: "Hello world",
			type: "text/vnd.tiddlywiki"
		});

		var widget = {
			wiki: wiki,
			editTitle: "MappingFallbackTest",
			editField: "text"
		};

		withBrowserFlag(false,function() {
			expect(EditWidget.prototype.getEditorType.call(widget)).toBe("text");
		});
	});

	it("should fall back to text editor in the browser when a mapped parser is unavailable", function() {
		var EditWidget = require("$:/core/modules/widgets/edit.js").edit;
		var wiki = new $tw.Wiki();
		wiki.addTiddler({
			title: "$:/config/EditorTypeMappings/application/x-unknown",
			text: "prosemirror"
		});
		wiki.addTiddler({
			title: "MissingParserFallbackTest",
			text: "Hello world",
			type: "application/x-unknown"
		});

		var widget = {
			wiki: wiki,
			editTitle: "MissingParserFallbackTest",
			editField: "text"
		};

		withBrowserFlag(true,function() {
			expect(EditWidget.prototype.getEditorType.call(widget)).toBe("text");
		});
	});

	it("should use prosemirror in the browser for markdown when the parser is available", function() {
		var EditWidget = require("$:/core/modules/widgets/edit.js").edit;
		var wiki = new $tw.Wiki();
		wiki.addTiddler({
			title: "$:/config/EditorTypeMappings/text/markdown",
			text: "prosemirror"
		});
		wiki.addTiddler({
			title: "MarkdownMappingTest",
			text: "# Heading",
			type: "text/markdown"
		});

		var widget = {
			wiki: wiki,
			editTitle: "MarkdownMappingTest",
			editField: "text"
		};

		withBrowserFlag(true,function() {
			expect($tw.Wiki.parsers["text/markdown"]).toBeTruthy();
			expect(EditWidget.prototype.getEditorType.call(widget)).toBe("prosemirror");
		});
	});
});

test-prosemirror-engine-ops.js.text:
/*\
title: test-prosemirror-engine-ops.js
type: application/javascript
tags: [[$:/tags/test-spec]]

Tests for ProseMirror engine text operation mapping logic.
These run in node without a real EditorView, testing the helper methods.

\*/

"use strict";

describe("ProseMirror engine operation mapping", () => {

	let buildSchema, ProseMirrorEngine;
	try {
		// engine.js imports browser-only prosemirror-view at the top level,
		// so in Node it will throw. We still test buildSchema and mark mapping
		// by importing the engine module which re-exports buildSchema.
		const mod = require("$:/plugins/tiddlywiki/prosemirror/core/engine.js");
		buildSchema = mod.buildSchema;
		ProseMirrorEngine = mod.ProseMirrorEngine;
	} catch(e) {
		// If engine.js cannot be loaded (missing prosemirror-view in Node),
		// try buildSchema from a lighter module or skip gracefully.
		try {
			// buildSchema only needs prosemirror-model and prosemirror-schema-basic.
			require("prosemirror-model").Schema;
			// If we got here, prosemirror-model is available but engine.js failed
			// due to prosemirror-view. Skip the tests.
		} catch(e2) {
			// No prosemirror at all, skip
		}
		return;
	}

	// Test buildSchema
	describe("buildSchema", () => {

		it("should export buildSchema function", () => {
			expect(typeof buildSchema).toBe("function");
		});

		it("should return a ProseMirror schema with expected node types", () => {
			const schema = buildSchema();
			expect(schema).toBeDefined();
			expect(schema.nodes).toBeDefined();
			expect(schema.nodes.doc).toBeDefined();
			expect(schema.nodes.paragraph).toBeDefined();
			expect(schema.nodes.heading).toBeDefined();
			expect(schema.nodes.code_block).toBeDefined();
			expect(schema.nodes.blockquote).toBeDefined();
			expect(schema.nodes.horizontal_rule).toBeDefined();
			expect(schema.nodes.image).toBeDefined();
			expect(schema.nodes.hard_break).toBeDefined();
			expect(schema.nodes.list).toBeDefined();
		});

		it("should have custom block types (pragma_block, opaque_block)", () => {
			const schema = buildSchema();
			expect(schema.nodes.pragma_block).toBeDefined();
			expect(schema.nodes.opaque_block).toBeDefined();
		});

		it("should have extended marks (underline, strike, superscript, subscript)", () => {
			const schema = buildSchema();
			expect(schema.marks.strong).toBeDefined();
			expect(schema.marks.em).toBeDefined();
			expect(schema.marks.code).toBeDefined();
			expect(schema.marks.link).toBeDefined();
			expect(schema.marks.underline).toBeDefined();
			expect(schema.marks.strike).toBeDefined();
			expect(schema.marks.superscript).toBeDefined();
			expect(schema.marks.subscript).toBeDefined();
		});

		it("should set image node attrs with tw-specific fields", () => {
			const schema = buildSchema();
			const imageSpec = schema.nodes.image.spec;
			expect(imageSpec.attrs.twSource).toBeDefined();
			expect(imageSpec.attrs.twKind).toBeDefined();
			expect(imageSpec.attrs.twTooltip).toBeDefined();
			expect(imageSpec.attrs.width).toBeDefined();
			expect(imageSpec.attrs.height).toBeDefined();
		});

		it("should mark superscript and subscript as mutually exclusive", () => {
			const schema = buildSchema();
			expect(schema.marks.superscript.spec.excludes).toBe("subscript");
			expect(schema.marks.subscript.spec.excludes).toBe("superscript");
		});
	});

	// Test _wrapSelectionToMark mapping (we instantiate a mock engine)
	describe("_wrapSelectionToMark mapping", () => {

		// Create a minimal mock engine to test the prototype method
		const proto = {};
		// Copy the method if it exists on ProseMirrorEngine prototype
		if(ProseMirrorEngine && ProseMirrorEngine.prototype._wrapSelectionToMark) {
			proto._wrapSelectionToMark = ProseMirrorEngine.prototype._wrapSelectionToMark;
		}

		if(proto._wrapSelectionToMark) {
			it("should map bold prefix/suffix to 'strong'", () => {
				expect(proto._wrapSelectionToMark("''", "''")).toBe("strong");
			});

			it("should map italic prefix/suffix to 'em'", () => {
				expect(proto._wrapSelectionToMark("//", "//")).toBe("em");
			});

			it("should map underline prefix/suffix to 'underline'", () => {
				expect(proto._wrapSelectionToMark("__", "__")).toBe("underline");
			});

			it("should map strikethrough prefix/suffix to 'strike'", () => {
				expect(proto._wrapSelectionToMark("~~", "~~")).toBe("strike");
			});

			it("should map superscript prefix/suffix to 'superscript'", () => {
				expect(proto._wrapSelectionToMark("^^", "^^")).toBe("superscript");
			});

			it("should map subscript prefix/suffix to 'subscript'", () => {
				expect(proto._wrapSelectionToMark(",,", ",,")).toBe("subscript");
			});

			it("should map backtick prefix/suffix to 'code'", () => {
				expect(proto._wrapSelectionToMark("`", "`")).toBe("code");
			});

			it("should return null for non-matching prefix/suffix", () => {
				expect(proto._wrapSelectionToMark("[[", "]]")).toBeNull();
				expect(proto._wrapSelectionToMark("{{", "}}")).toBeNull();
				expect(proto._wrapSelectionToMark("<<<", "<<<")).toBeNull();
			});

			it("should return null for asymmetric prefix/suffix", () => {
				expect(proto._wrapSelectionToMark("''", "//")).toBeNull();
			});

			it("should return null for null/empty args", () => {
				expect(proto._wrapSelectionToMark(null, null)).toBeNull();
				expect(proto._wrapSelectionToMark("", "")).toBeNull();
			});
		}
	});
});

test-prosemirror-markdown-shortcuts.js.text:
/*\
title: test-prosemirror-markdown-shortcuts.js
type: application/javascript
tags: [[$:/tags/test-spec]]

Tests for Markdown shortcut enablement defaults in ProseMirror.

\*/

"use strict";

describe("ProseMirror markdown shortcut defaults", function() {
	let buildSchema, markdownShortcuts;
	try {
		buildSchema = require("$:/plugins/tiddlywiki/prosemirror/core/schema.js").buildSchema;
		markdownShortcuts = require("$:/plugins/tiddlywiki/prosemirror/features/markdown-shortcuts.js");
	} catch(e) {
		return;
	}

	function makeWiki(config) {
		return {
			getTiddlerText: function(title, defaultText) {
				return Object.prototype.hasOwnProperty.call(config, title) ? config[title] : defaultText;
			}
		};
	}

	it("should enable markdown shortcuts by default for markdown tiddlers", function() {
		const wiki = makeWiki({});
		expect(markdownShortcuts.shouldEnableMarkdownShortcuts(wiki, "text/markdown")).toBe(true);
		expect(markdownShortcuts.getMarkdownInputRules(wiki, buildSchema(), "text/markdown").length).toBeGreaterThan(0);
	});

	it("should keep markdown shortcuts disabled by default for wikitext tiddlers", function() {
		const wiki = makeWiki({});
		expect(markdownShortcuts.shouldEnableMarkdownShortcuts(wiki, "text/vnd.tiddlywiki")).toBe(false);
		expect(markdownShortcuts.getMarkdownInputRules(wiki, buildSchema(), "text/vnd.tiddlywiki").length).toBe(0);
	});

	it("should allow disabling markdown auto-shortcuts for markdown tiddlers", function() {
		const wiki = makeWiki({
			"$:/config/prosemirror/markdown-shortcuts/auto-for-markdown": "no"
		});
		expect(markdownShortcuts.shouldEnableMarkdownShortcuts(wiki, "text/x-markdown")).toBe(false);
	});

	it("should allow explicitly enabling markdown shortcuts for all editor types", function() {
		const wiki = makeWiki({
			"$:/config/prosemirror/markdown-shortcuts": "yes",
			"$:/config/prosemirror/markdown-shortcuts/auto-for-markdown": "no"
		});
		expect(markdownShortcuts.shouldEnableMarkdownShortcuts(wiki, "text/vnd.tiddlywiki")).toBe(true);
		expect(markdownShortcuts.getMarkdownInputRules(wiki, buildSchema(), "text/vnd.tiddlywiki").length).toBeGreaterThan(0);
	});
});

test-prosemirror-menu-elements.js.text:
/*\
title: test-prosemirror-menu-elements.js
type: application/javascript
tags: [[$:/tags/test-spec]]

Tests for menu-elements.js (EditorAction collection, snippet loading, etc.)
\*/

"use strict";

describe("ProseMirror menu-elements tests", () => {

	let getAllMenuElements, flattenMenuElementsWithGroup, getBuiltinActionCommands;
	let buildSchema;
	try {
		const mod = require("$:/plugins/tiddlywiki/prosemirror/features/slash-menu/menu-elements.js");
		getAllMenuElements = mod.getAllMenuElements;
		flattenMenuElementsWithGroup = mod.flattenMenuElementsWithGroup;
		getBuiltinActionCommands = mod.getBuiltinActionCommands;
		buildSchema = require("$:/plugins/tiddlywiki/prosemirror/core/engine.js").buildSchema;
	} catch(e) {
		// prosemirror dependencies not available in this test env
		return;
	}

	describe("getBuiltinActionCommands", () => {

		it("should return an object with command functions", () => {
			const schema = buildSchema();
			const cmds = getBuiltinActionCommands(schema);
			expect(cmds).toBeDefined();
			expect(typeof cmds).toBe("object");
		});

		it("should have entries for common actions", () => {
			const schema = buildSchema();
			const cmds = getBuiltinActionCommands(schema);
			const expectedKeys = [
				"codeblock", "blockquote", "paragraph",
				"heading1", "heading2", "heading3", "heading4", "heading5", "heading6",
				"horizontal-rule", "bold", "italic", "underline", "strikethrough", "code-inline"
			];
			for(let i = 0; i < expectedKeys.length; i++) {
				expect(typeof cmds[expectedKeys[i]]).toBe("function",
					"Expected command for '" + expectedKeys[i] + "' to be a function");
			}
		});
	});

	describe("getAllMenuElements", () => {

		it("should return an array", () => {
			const schema = buildSchema();
			const elements = getAllMenuElements($tw.wiki, schema);
			expect(Array.isArray(elements)).toBe(true);
		});

		it("should include EditorAction tiddler-based elements", () => {
			const schema = buildSchema();
			const elements = getAllMenuElements($tw.wiki, schema);
			// Should have some action-* items from the editor-actions/*.tid files
			const actionItems = elements.filter((e) => e && e.id && e.id.startsWith("action-"));
			expect(actionItems.length).toBeGreaterThan(0);
		});

		it("should include block-type category items", () => {
			const schema = buildSchema();
			const elements = getAllMenuElements($tw.wiki, schema);
			const blockTypeItems = elements.filter((e) => e && e.category === "block-type" && e.type === "command");
			expect(blockTypeItems.length).toBeGreaterThan(0);
		});
	});

	describe("flattenMenuElementsWithGroup", () => {

		it("should flatten submenus into group headers + items", () => {
			const input = [
				{ id: "a", label: "A", type: "command", available: () => true },
				{
					id: "sub1", label: "Sub 1", type: "submenu", available: () => true,
					elements: [
						{ id: "b", label: "B", type: "command", available: () => true },
						{ id: "c", label: "C", type: "command", available: () => true }
					]
				}
			];
			const flat = flattenMenuElementsWithGroup(input);
			expect(flat.length).toBe(4); // a, group-sub1, b, c
			expect(flat[0].id).toBe("a");
			expect(flat[1].id).toBe("group-sub1");
			expect(flat[1].type).toBe("group");
			expect(flat[2].id).toBe("b");
			expect(flat[3].id).toBe("c");
		});

		it("should handle empty array", () => {
			expect(flattenMenuElementsWithGroup([]).length).toBe(0);
		});
	});
});

test-prosemirror-widget-utils.js.text:
/*\
title: test-prosemirror-widget-utils.js
type: application/javascript
tags: [[$:/tags/test-spec]]

Tests parseWidget and parseAttributes from widget-block/utils.js.
These utilities parse <<macro "args">> invocations from user input.

\*/

"use strict";

describe("ProseMirror parseWidget tests", () => {

	let parseWidget, parseAttributes;
	try {
		const utils = require("$:/plugins/tiddlywiki/prosemirror/blocks/widget/utils.js");
		parseWidget = utils.parseWidget;
		parseAttributes = utils.parseAttributes;
	} catch(e) {
		return;
	}

	// --- Basic macro detection ---

	it("should parse a simple macro without args", () => {
		const result = parseWidget("<<myMacro>>");
		expect(result).not.toBeNull();
		expect(result.widgetName).toBe("myMacro");
	});

	it("should parse a macro with leading/trailing whitespace", () => {
		const result = parseWidget("  <<myMacro>>  ");
		expect(result).not.toBeNull();
		expect(result.widgetName).toBe("myMacro");
	});

	it("should return null for non-macro text", () => {
		expect(parseWidget("just text")).toBeNull();
		expect(parseWidget("")).toBeNull();
		expect(parseWidget("<single-bracket>")).toBeNull();
	});

	// --- Macro name validation ---

	it("should parse a macro with hyphens in name", () => {
		const result = parseWidget("<<list-links>>");
		expect(result).not.toBeNull();
		expect(result.widgetName).toBe("list-links");
	});

	it("should parse a macro with underscores in name", () => {
		const result = parseWidget("<<my_macro>>");
		expect(result).not.toBeNull();
		expect(result.widgetName).toBe("my_macro");
	});

	// --- Positional arguments ---

	it("should parse a single quoted positional argument", () => {
		const result = parseWidget('<<myMacro "hello world">>');
		expect(result).not.toBeNull();
		expect(result.attributes["0"]).toBe("hello world");
	});

	it("should parse a single-quoted positional argument", () => {
		const result = parseWidget("<<myMacro 'hello world'>>");
		expect(result).not.toBeNull();
		expect(result.attributes["0"]).toBe("hello world");
	});

	// --- Named arguments ---

	it("should parse named key=value arguments", () => {
		const result = parseWidget('<<myMacro key:"value">>');
		expect(result).not.toBeNull();
		expect(result.attributes.key).toBe("value");
	});

	// --- Critical: >> inside quoted strings ---

	it("should handle >> inside double-quoted attribute values", () => {
		const input = '<<myMacro "value with >> inside">>';
		const result = parseWidget(input);
		expect(result).not.toBeNull();
		expect(result.widgetName).toBe("myMacro");
		expect(result.attributes["0"]).toBe("value with >> inside");
	});

	it("should handle >> inside single-quoted attribute values", () => {
		const input = "<<myMacro 'value with >> inside'>>";
		const result = parseWidget(input);
		expect(result).not.toBeNull();
		expect(result.widgetName).toBe("myMacro");
		expect(result.attributes["0"]).toBe("value with >> inside");
	});

	// --- Critical: nested << >> ---

	it("should handle nested macros in attribute (triple-quote delimited)", () => {
		const input = '<<myMacro """<<innerMacro>>""">>';
		const result = parseWidget(input);
		expect(result).not.toBeNull();
		expect(result.widgetName).toBe("myMacro");
	});

	// --- TiddlyWiki filter syntax in arguments ---

	it("should parse filter argument with square brackets", () => {
		const input = '<<list-links "[tag[task]sort[title]]">>';
		const result = parseWidget(input);
		expect(result).not.toBeNull();
		expect(result.widgetName).toBe("list-links");
		expect(result.attributes["0"]).toBe("[tag[task]sort[title]]");
		expect(result.orderedAttributes[0].name).toBe("0");
		expect(result.orderedAttributes[0].quoted).toBe(true);
	});

	// --- Complex real-world cases ---

	it("should parse macro with multiple arguments", () => {
		const input = '<<myMacro "arg1" key:"val2">>';
		const result = parseWidget(input);
		expect(result).not.toBeNull();
		expect(result.widgetName).toBe("myMacro");
		expect(result.attributes["0"]).toBe("arg1");
		expect(result.attributes.key).toBe("val2");
	});

	it("should parse a macro with colon-delimited named args", () => {
		const input = '<<image-picker actions:"<$action-sendmessage $message=\'test\'/>"  >>';
		const result = parseWidget(input);
		expect(result).not.toBeNull();
		expect(result.widgetName).toBe("image-picker");
	});

	// --- parseAttributes edge cases ---

	it("should parse empty attributes string", () => {
		const result = parseAttributes("");
		expect(Object.keys(result).length).toBe(0);
	});

	it("should parse null/undefined attributes", () => {
		const result = parseAttributes(null);
		expect(Object.keys(result).length).toBe(0);
	});

	it("should parse unquoted positional values", () => {
		const result = parseAttributes("hello");
		expect(result["0"]).toBe("hello");
	});
});
